import{_ as o,a as e,M as r,o as a}from"./chunks/framework.BzjwFSRk.js";const u=JSON.parse('{"title":"Список оборудования ЦМИТ \\"Академия\\", Москва","description":"","frontmatter":{"title":"Список оборудования ЦМИТ \\"Академия\\", Москва","date":"2015-05-28","cover":"h9qRUIXj_AQ.jpg"},"headers":[],"relativePath":"theory/repost/tsmit-akademiya-moskva/index.md","filePath":"theory/repost/tsmit-akademiya-moskva/index.md"}'),s={name:"theory/repost/tsmit-akademiya-moskva/index.md"};function n(p,t,i,d,m,g){return a(),e("div",null,[...t[0]||(t[0]=[r('<p>Основная цель создания <a href="/workshop/archive/tsmit-akademiya/">Центра молодежного инновационного творчества &quot;Академия&quot; (ЦМИТ &quot;Академия&quot;)</a> - пробудить интерес детей и молодежи к естественным наукам и современным технологиям, научно-исследовательской и инновационной деятельности.</p><p>После краткого введения дети начинают самостоятельно воплощать свои идеи в жизнь. Мы не ищем ответы за них, мы только побуждаем их искать собственные творческие решения.</p><p>Мы знаем точно - дети с удовольствием и большим вниманием занимаются практической работой, исследуют, конструируют и постоянно придумывают что-то новое! Все это происходит под присмотром и контролем стажеров и сотрудников Центра.</p><p>ЦМИТ - это не просто набор оборудования и материалов. Это комплекс творческих подходов к обучению цифровому производству и изготовлению &quot;почти всего&quot; 😃</p><h3 id="список-оборудования-цмит-академия" tabindex="-1">Список оборудования ЦМИТ &quot;Академия&quot;. <a class="header-anchor" href="#список-оборудования-цмит-академия" aria-label="Permalink to &quot;Список оборудования ЦМИТ &quot;Академия&quot;.&quot;">​</a></h3><p><strong>Epilog mini</strong> Технология обработки: Лазерная резка/гравировка Резка: дерево, фанера(&lt;10мм), акрил, пластмасс, резина, кожа Гравировка: + стекло, мрамор, кожа, анодированный алюминий Рабочая область: 610х305 мм Мощность: 30 Вт</p><p><strong>PICASO 3D Designer</strong> Технология печати: FDM Материал печати: пластики PLA и ABS Область печати: 200x200x210 мм Скорость печати: до 30 см3/час Минимальная толщина слоя: 0,05мм</p><p><strong>UP! Plus</strong> Технология печати: FDM Материал печати: пластики PLA и ABS Область печати: 140х140х135 мм Скорость печати: до 10 см3/час Минимальная толщина слоя: 0,15мм</p><p><strong>MakerBot Replicator2</strong> Технология печати: FDM Материал печати: пластик PLA Область печати: 285х153х155 мм Скорость печати: до 24 см3/час Минимальная толщина слоя: 0,10мм</p><p><strong>CubeX Trio</strong> Технология печати: FDM Материал печати: пластики PLA и ABS Область печати: 275х265х240 мм Скорость печати: до 15 см3/час Минимальная толщина слоя: 0,10мм</p><p><strong>BitfromBytes 3D Touch Double HEAD</strong> Технология печати: FDM Материал печати: пластики PLA и ABS Область печати: 230х275х210 мм Скорость печати: до 54 см3/час Минимальная толщина слоя: 0,125мм</p><p><strong>Roland MDX-20</strong> Технология обработки: фрезерование/механическое 3D-сканировние Материал: ювелирный воск, модельные материалы, оргстекло и мягкие металлы, такие как латунь и алюминий Рабочая область: 203х152х60 мм Точность сканирования: до 0,05 мм</p><p><strong>Roland MDX-40</strong> Технология обработки: фрезерование/механическое 3D-сканировние Материал: ювелирный воск, модельные материалы, дерево, оргстекло, латунь, алюминий, медь, бронза, магний Рабочая область: 305x305x105 мм Частота вращения шпинделя: до 15000 об/мин Механическое разрешение: 0,002 мм</p><p><strong>Roland Servo GX-300</strong> Технология обработки: Режущий плоттер Контурная резка: виниловые, светоотражающие, трафаретные пленки, баннерная ткань, термотрансферные и пескоструйные материалы Ширина материала: 50-915 мм Макс. область резки: 737x24998 мм Давление ножа: 20-350 грамм Разрешение: 0,025 мм</p>',14)])])}const c=o(s,[["render",n]]);export{u as __pageData,c as default};
